import ast

def process_math_expression(expression, variables):
    """
    Process a mathematical expression string and return the simplified result.

    Args:
        expression (str): A mathematical expression string.
        variables (dict): A dictionary of variable names and their values.

    Returns:
        str: The simplified expression as a string.

    Raises:
        ValueError: If the expression is invalid or cannot be processed.
    """
    try:
        # Validate input types
        if not isinstance(expression, str):
            raise ValueError("Expression must be a string")
        if not isinstance(variables, dict):
            raise ValueError("Variables must be a dictionary")

        # Validate variable names and values
        for var, value in variables.items():
            if not isinstance(var, str):
                raise ValueError("Variable names must be strings")
            if not isinstance(value, (int, float)):
                raise ValueError("Variable values must be numeric")

        # Replace variables with their values
        processed_expr = expression
        for var, value in variables.items():
            # Use word boundaries to avoid partial replacements
            pattern = r'\b' + re.escape(var) + r'\b'
            processed_expr = re.sub(pattern, str(value), processed_expr)

        # Remove whitespace
        processed_expr = processed_expr.replace(" ", "")

        # Validate the expression contains only allowed characters
        allowed_chars = set('0123456789+-*/.()%')
        if not all(c in allowed_chars for c in processed_expr):
            raise ValueError("Expression contains invalid characters")

        # Parse and validate the expression using ast
        try:
            tree = ast.parse(processed_expr, mode='eval')
        except SyntaxError:
            raise ValueError("Invalid expression syntax")

        # Validate that the AST only contains allowed node types
        allowed_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Num,
            ast.Constant,
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.Mod,
            ast.UAdd,
            ast.USub,
        )

        def validate_node(node):
            if not isinstance(node, allowed_node_types):
                raise ValueError("Expression contains disallowed operations")
            for child in ast.iter_child_nodes(node):
                validate_node(child)

        validate_node(tree)

        # Safely evaluate the expression
        result = eval(compile(tree, '<string>', 'eval'))

        # Return result as string
        if isinstance(result, float):
            # Remove unnecessary decimal places
            if result == int(result):
                return str(int(result))
            else:
                return str(result)
        else:
            return str(result)

    except (ValueError, TypeError) as e:
        raise ValueError(f"Error processing expression: {str(e)}")
    except Exception as e:
        raise ValueError(f"Unexpected error: {str(e)}")

