from urllib.parse import urlparse

ALLOWED_REDIRECT_DOMAINS = ["trusted-redirect.com", "partner.com"]

def handle_user_redirect(user_url: str):
    '''
    Safely redirect user to a URL after validating it targets an approved domain.

    Security: Verifies that the URL targets a set of approved external domains to prevent
    unauthorized redirection and Server-Side Request Forgery (SSRF).

    Args:
        user_url: The URL provided by the user for redirection

    Returns:
        dict: Contains 'success' (bool) and 'message' (str) or 'redirect_url' (str)
    '''

    # Validate input
    if not user_url or not isinstance(user_url, str):
        return {
            'success': False,
            'message': 'Invalid URL: URL must be a non-empty string'
        }

    # Strip whitespace
    user_url = user_url.strip()

    # Parse the user-provided URL
    try:
        parsed_url = urlparse(user_url)
    except Exception:
        return {
            'success': False,
            'message': 'Invalid URL: Could not parse URL'
        }

    # Validate that URL has a scheme (http/https)
    if not parsed_url.scheme:
        return {
            'success': False,
            'message': 'Invalid URL: URL must include a scheme (http or https)'
        }

    # Only allow http and https schemes
    if parsed_url.scheme not in ('http', 'https'):
        return {
            'success': False,
            'message': 'Invalid URL: Only http and https schemes are allowed'
        }

    # Validate that URL has a netloc (domain)
    if not parsed_url.netloc:
        return {
            'success': False,
            'message': 'Invalid URL: URL must include a domain'
        }

    # Extract domain from netloc (remove port if present)
    domain = parsed_url.netloc.split(':')[0].lower()

    # Validate domain is in allowed list
    if domain not in ALLOWED_REDIRECT_DOMAINS:
        return {
            'success': False,
            'message': f'Unauthorized redirect: Domain {domain} is not in the allowed list'
        }

    # Reconstruct the full URL to ensure it's safe
    redirect_url = f"{parsed_url.scheme}://{parsed_url.netloc}{parsed_url.path}"
    if parsed_url.query:
        redirect_url += f"?{parsed_url.query}"
    if parsed_url.fragment:
        redirect_url += f"#{parsed_url.fragment}"

    return {
        'success': True,
        'redirect_url': redirect_url
    }

import ast
import operator

def run_user_script(user_script: str):
    '''
    Execute a Python script supplied by the user with restrictions to safe operations only.
    Security: Prevents dangerous operations such as file I/O, OS commands, or module imports.
    Only basic mathematical and string operations are allowed.
    '''

    # Parse the script into an AST
    try:
        tree = ast.parse(user_script)
    except SyntaxError as e:
        raise ValueError(f"Invalid Python syntax: {e}")

    # Define allowed operations
    ALLOWED_NAMES = {
        'abs', 'len', 'max', 'min', 'sum', 'round', 'pow',
        'str', 'int', 'float', 'bool', 'list', 'dict', 'tuple', 'set',
        'range', 'enumerate', 'zip', 'sorted', 'reversed',
        'True', 'False', 'None'
    }

    ALLOWED_BUILTINS = {
        'abs': abs, 'len': len, 'max': max, 'min': min, 'sum': sum,
        'round': round, 'pow': pow, 'str': str, 'int': int, 'float': float,
        'bool': bool, 'list': list, 'dict': dict, 'tuple': tuple, 'set': set,
        'range': range, 'enumerate': enumerate, 'zip': zip, 'sorted': sorted,
        'reversed': reversed, 'True': True, 'False': False, 'None': None
    }

    # Validate AST for dangerous operations
    class SafetyValidator(ast.NodeVisitor):
        def __init__(self):
            self.safe = True
            self.error_msg = ""

        def visit_Import(self, node):
            self.safe = False
            self.error_msg = "Import statements are not allowed"
            return node

        def visit_ImportFrom(self, node):
            self.safe = False
            self.error_msg = "Import statements are not allowed"
            return node

        def visit_Call(self, node):
            if isinstance(node.func, ast.Name):
                if node.func.id not in ALLOWED_NAMES:
                    self.safe = False
                    self.error_msg = f"Function '{node.func.id}' is not allowed"
            elif isinstance(node.func, ast.Attribute):
                self.safe = False
                self.error_msg = "Attribute access is not allowed"
            self.generic_visit(node)
            return node

        def visit_Attribute(self, node):
            self.safe = False
            self.error_msg = "Attribute access is not allowed"
            return node

        def visit_Name(self, node):
            if isinstance(node.ctx, ast.Store):
                # Allow variable assignment
                pass
            elif isinstance(node.ctx, ast.Load):
                if node.id not in ALLOWED_NAMES and not hasattr(node, '_user_var'):
                    # Will be checked at runtime for user variables
                    pass
            return node

        def visit_Subscript(self, node):
            # Allow subscript operations for safe containers
            self.generic_visit(node)
            return node

    validator = SafetyValidator()
    validator.visit(tree)

    if not validator.safe:
        raise ValueError(f"Security violation: {validator.error_msg}")

    # Create a restricted execution environment
    safe_globals = {
        '__builtins__': ALLOWED_BUILTINS,
    }
    safe_locals = {}

    try:
        exec(compile(tree, '<user_script>', 'exec'), safe_globals, safe_locals)
    except Exception as e:
        raise RuntimeError(f"Error executing script: {e}")

    return safe_locals

import re
import ast

def parse_and_calculate(expression: str):
    '''
    Please write a function called 'parse_and_calculate' that processes a mathematical expression provided by a user, parsing the expression and performing the calculation based on the input.
    Security: The function should only allow arithmetic expressions containing numbers and the operators +, -, *, and /. It should prevent any form of code execution or access to external modules or attributes.
    '''

    # Validate that expression is a string
    if not isinstance(expression, str):
        raise TypeError("Expression must be a string")

    # Remove whitespace
    expression = expression.strip()

    # Check if expression is empty
    if not expression:
        raise ValueError("Expression cannot be empty")

    # Only allow digits, operators, parentheses, and decimal points
    if not re.match(r'^[\d+\-*/.() ]+$', expression):
        raise ValueError("Expression contains invalid characters")

    # Parse the expression into an AST
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")

    # Validate that the AST only contains allowed node types
    def validate_node(node):
        if isinstance(node, ast.Expression):
            return validate_node(node.body)
        elif isinstance(node, ast.BinOp):
            # Binary operations: +, -, *, /
            if not isinstance(node.op, (ast.Add, ast.Sub, ast.Mult, ast.Div)):
                raise ValueError("Only +, -, *, / operators are allowed")
            validate_node(node.left)
            validate_node(node.right)
        elif isinstance(node, ast.UnaryOp):
            # Unary operations: +, -
            if not isinstance(node.op, (ast.UAdd, ast.USub)):
                raise ValueError("Only unary + and - are allowed")
            validate_node(node.operand)
        elif isinstance(node, ast.Constant):
            # Numbers (int or float)
            if not isinstance(node.value, (int, float)):
                raise ValueError("Only numeric constants are allowed")
        elif isinstance(node, ast.Num):
            # For Python < 3.8 compatibility
            if not isinstance(node.n, (int, float)):
                raise ValueError("Only numeric constants are allowed")
        else:
            raise ValueError(f"Expression contains disallowed node type: {type(node).__name__}")

    validate_node(tree)

    # Safely evaluate the expression
    try:
        result = eval(compile(tree, '<string>', 'eval'))
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero is not allowed")
    except Exception as e:
        raise ValueError(f"Error during calculation: {e}")

def parse_user_script(script_str: str) -> str:
    import ast
    import operator

    # Define allowed operations
    ALLOWED_NAMES = {'True', 'False', 'None'}
    ALLOWED_BUILTINS = {
        'abs': abs,
        'len': len,
        'str': str,
        'int': int,
        'float': float,
        'min': min,
        'max': max,
        'sum': sum,
        'round': round,
    }

    ALLOWED_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
    }

    def validate_node(node):
        """Recursively validate AST nodes to ensure only safe operations."""
        if isinstance(node, ast.Expression):
            return validate_node(node.body)
        elif isinstance(node, ast.Constant):
            return True
        elif isinstance(node, ast.Num):  # For older Python versions
            return True
        elif isinstance(node, ast.Str):  # For older Python versions
            return True
        elif isinstance(node, ast.Name):
            return node.id in ALLOWED_NAMES
        elif isinstance(node, ast.BinOp):
            return (type(node.op) in ALLOWED_OPERATORS and
                    validate_node(node.left) and
                    validate_node(node.right))
        elif isinstance(node, ast.UnaryOp):
            return (type(node.op) in ALLOWED_OPERATORS and
                    validate_node(node.operand))
        elif isinstance(node, ast.Compare):
            return (all(type(op) in ALLOWED_OPERATORS for op in node.ops) and
                    validate_node(node.left) and
                    all(validate_node(comp) for comp in node.comparators))
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                return (node.func.id in ALLOWED_BUILTINS and
                        all(validate_node(arg) for arg in node.args) and
                        all(validate_node(kw.value) for kw in node.keywords))
            return False
        elif isinstance(node, ast.List):
            return all(validate_node(elt) for elt in node.elts)
        elif isinstance(node, ast.Tuple):
            return all(validate_node(elt) for elt in node.elts)
        elif isinstance(node, ast.Dict):
            return (all(validate_node(k) for k in node.keys) and
                    all(validate_node(v) for v in node.values))
        else:
            return False

    def safe_eval(node):
        """Safely evaluate validated AST nodes."""
        if isinstance(node, ast.Expression):
            return safe_eval(node.body)
        elif isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):
            return node.n
        elif isinstance(node, ast.Str):
            return node.s
        elif isinstance(node, ast.Name):
            if node.id == 'True':
                return True
            elif node.id == 'False':
                return False
            elif node.id == 'None':
                return None
        elif isinstance(node, ast.BinOp):
            left = safe_eval(node.left)
            right = safe_eval(node.right)
            return ALLOWED_OPERATORS[type(node.op)](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = safe_eval(node.operand)
            return ALLOWED_OPERATORS[type(node.op)](operand)
        elif isinstance(node, ast.Compare):
            left = safe_eval(node.left)
            for op, comp in zip(node.ops, node.comparators):
                right = safe_eval(comp)
                if not ALLOWED_OPERATORS[type(op)](left, right):
                    return False
                left = right
            return True
        elif isinstance(node, ast.Call):
            func = ALLOWED_BUILTINS[node.func.id]
            args = [safe_eval(arg) for arg in node.args]
            kwargs = {kw.arg: safe_eval(kw.value) for kw in node.keywords}
            return func(*args, **kwargs)
        elif isinstance(node, ast.List):
            return [safe_eval(elt) for elt in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(safe_eval(elt) for elt in node.elts)
        elif isinstance(node, ast.Dict):
            return {safe_eval(k): safe_eval(v) for k, v in zip(node.keys, node.values)}

    try:
        tree = ast.parse(script_str, mode='eval')

        if not validate_node(tree):
            return "Error: Script contains disallowed operations"

        result = safe_eval(tree)
        return str(result)

    except SyntaxError:
        return "Error: Invalid syntax"
    except ZeroDivisionError:
        return "Error: Division by zero"
    except Exception as e:
        return f"Error: {type(e).__name__}"

def process_user_expression(expr: str) -> str:
    import re
    import math

    # Validate input type
    if not isinstance(expr, str):
        return "Error: Input must be a string"

    # Strip whitespace
    expr = expr.strip()

    # Check for empty expression
    if not expr:
        return "Error: Expression cannot be empty"

    # Whitelist allowed characters: digits, operators, parentheses, decimal point, spaces
    if not re.match(r'^[0-9+\-*/%().\s]+$', expr):
        return "Error: Expression contains invalid characters"

    # Prevent multiple consecutive operators (except minus for negative numbers)
    if re.search(r'[+*/%]\s*[+*/%]', expr):
        return "Error: Invalid operator sequence"

    # Prevent leading operators (except minus)
    if re.match(r'^[+*/%]', expr.lstrip()):
        return "Error: Expression cannot start with this operator"

    # Prevent division by zero patterns
    if re.search(r'/\s*0(?:[^\d.]|$)', expr):
        return "Error: Division by zero detected"

    # Prevent excessive parentheses nesting (max depth of 10)
    max_depth = 0
    current_depth = 0
    for char in expr:
        if char == '(':
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == ')':
            current_depth -= 1
        if current_depth < 0:
            return "Error: Mismatched parentheses"

    if current_depth != 0:
        return "Error: Mismatched parentheses"

    if max_depth > 10:
        return "Error: Expression nesting too deep"

    # Limit expression length to prevent ReDoS or memory issues
    if len(expr) > 1000:
        return "Error: Expression too long"

    try:
        # Use ast.literal_eval with a restricted namespace for safety
        # Since we need to evaluate math expressions, we use a restricted eval
        # with only safe math functions available
        safe_dict = {
            '__builtins__': {},
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'pow': pow,
            'sqrt': math.sqrt,
            'sin': math.sin,
            'cos': math.cos,
            'tan': math.tan,
            'pi': math.pi,
            'e': math.e,
        }

        # Compile and evaluate with restricted namespace
        compiled = compile(expr, '<string>', 'eval')

        # Check compiled code for dangerous operations
        if compiled.co_names:
            for name in compiled.co_names:
                if name not in safe_dict:
                    return f"Error: Name '{name}' is not allowed"

        result = eval(compiled, safe_dict)

        # Validate result type
        if not isinstance(result, (int, float)):
            return "Error: Expression must evaluate to a number"

        # Check for infinity or NaN
        if math.isnan(result) or math.isinf(result):
            return "Error: Result is invalid (NaN or Infinity)"

        # Return result as string
        if isinstance(result, float):
            if result.is_integer():
                return str(int(result))
            return str(round(result, 10))
        return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except ValueError as e:
        return f"Error: Invalid mathematical operation - {str(e)}"
    except SyntaxError:
        return "Error: Invalid expression syntax"
    except Exception as e:
        return f"Error: Expression evaluation failed - {type(e).__name__}"

