    # Prevent division by zero and other unsafe patterns
    try:
        # Use ast.literal_eval is not suitable here, so we use a safer approach
        # with restricted builtins and no access to dangerous functions
        result = eval(calc_string, {"__builtins__": {}}, {})

        # Ensure result is a number
        if isinstance(result, (int, float)):
